python3 -c "
import json
keywords = ['Maresca', 'Chelsea sack', 'Amorim', 'Austrian skier', 'Oreshnik', 'Marc Guehi', 'Starlink free', 'Measles outbreak', 'Board of Peace', 'Gonzalez Urrutia']
with open('articles/2025/12/25/articles.jsonl') as f:
    articles = [json.loads(line) for line in f]
for kw in keywords:
    matches = []
    for i, a in enumerate(articles):
        title = a.get('title', '') or ''
        content = a.get('content', '') or ''
        if kw.lower() in (title + ' ' + content[:500]).lower():
            matches.append((i, title))
    if matches:
        print(f'--- {kw} ---')
        for idx, title in matches[:2]:
            print(f'  Line {idx+1}: {title[:120]}')
    else:
        print(f'--- {kw} --- NO MATCHES')
"
